  59→    // 转录服务广播接收器
  60→    val transcriptionQueueReceiver = remember {
  61→        object : BroadcastReceiver() {
  62→            override fun onReceive(context: Context?, intent: Intent?) {
  63→                when (intent?.action) {
  64→                    TranscriptionService.ACTION_PROGRESS -> {
  65→                        val message = intent.getStringExtra(TranscriptionService.EXTRA_MESSAGE) ?: ""
  66→                        val progress = intent.getIntExtra(TranscriptionService.EXTRA_PROGRESS, 0)
  67→                        // 从消息中提取当前转录的视频名称
  68→                        val currentVideo = message.substringBefore(")").trim()
  69→                        viewModel.updateTranscriptionQueue(currentVideo, uiState.transcriptionQueue, progress, message)
  70→                    }
  71→                    TranscriptionService.ACTION_QUEUE_UPDATE -> {
  72→                        val queueArray = intent.getStringArrayExtra(TranscriptionService.EXTRA_QUEUE_LIST)
  73→                        val queueList = queueArray?.toList() ?: emptyList()
  74→                        viewModel.updateTranscriptionQueue(uiState.transcribingVideo, queueList, uiState.transcriptionProgress, uiState.transcriptionMessage)
  75→                    }
  76→                    TranscriptionService.ACTION_COMPLETED -> {
  77→                        val success = intent.getBooleanExtra(TranscriptionService.EXTRA_SUCCESS, false)
  78→                        val videoPath = intent.getStringExtra(TranscriptionService.EXTRA_VIDEO_PATH)
  79→                        val vttPath = intent.getStringExtra(TranscriptionService.EXTRA_VTT_PATH)
  80→                        if (success && videoPath != null && vttPath != null) {
  81→                            viewModel.transcriptionCompleted(videoPath, vttPath)
  82→                        } else {
  83→                            viewModel.transcriptionCompleted()
  84→                        }
  85→                    }
  86→                }
  87→            }
