  96→        context.registerReceiver(transcriptionQueueReceiver, progressFilter, android.content.Context.RECEIVER_NOT_EXPORTED)
  97→        context.registerReceiver(transcriptionQueueReceiver, queueFilter, android.content.Context.RECEIVER_NOT_EXPORTED)
  98→        context.registerReceiver(transcriptionQueueReceiver, completedFilter, android.content.Context.RECEIVER_NOT_EXPORTED)
