 596→/**
 597→ * 下载进度卡片组件
 598→ */
 599→@Composable
 600→private fun DownloadProgressCard(
 601→    task: DownloadTask,
 602→    onCancel: () -> Unit,
 603→    formatFileSize: (Long) -> String,
 604→    formatSpeed: (Long) -> String,
 605→    formatRemainingTime: (Long) -> String,
 606→    getStatusText: (DownloadStatus) -> String
 607→) {
 608→    Card(
 609→        modifier = Modifier.fillMaxWidth(),
 610→        colors = CardDefaults.cardColors(
 611→            containerColor = when (task.status) {
 612→                DownloadStatus.FAILED, DownloadStatus.CANCELLED -> MaterialTheme.colorScheme.errorContainer
 613→                DownloadStatus.WAITING_FOR_AUTH -> MaterialTheme.colorScheme.tertiaryContainer
 614→                else -> MaterialTheme.colorScheme.primaryContainer
 615→            }
 616→        )
 617→    ) {
 618→        Column(modifier = Modifier.padding(16.dp)) {
 619→            // 标题和状态
 620→            Row(
 621→                modifier = Modifier.fillMaxWidth(),
 622→                horizontalArrangement = Arrangement.SpaceBetween,
 623→                verticalAlignment = Alignment.CenterVertically
 624→            ) {
 625→                Column(Modifier.weight(1f)) {
 626→                    Text(
 627→                        task.title,
 628→                        style = MaterialTheme.typography.titleSmall,
 629→                        maxLines = 1,
 630→                        overflow = TextOverflow.Ellipsis
 631→                    )
 632→                    Text(
 633→                        getStatusText(task.status),
 634→                        style = MaterialTheme.typography.bodySmall,
 635→                        color = when (task.status) {
 636→                            DownloadStatus.FAILED, DownloadStatus.CANCELLED -> MaterialTheme.colorScheme.error
 637→                            DownloadStatus.WAITING_FOR_AUTH -> MaterialTheme.colorScheme.onTertiaryContainer
 638→                            else -> MaterialTheme.colorScheme.onPrimaryContainer
 639→                        }
 640→                    )
 641→                }
 642→
 643→                // 取消按钮
 644→                if (task.status == DownloadStatus.DOWNLOADING || task.status == DownloadStatus.FETCHING_INFO) {
 645→                    IconButton(onClick = onCancel) {
 646→                        Icon(Icons.Default.Close, "取消", tint = MaterialTheme.colorScheme.error)
 647→                    }
 648→                }
 649→            }
 650→
 651→            Spacer(Modifier.height(12.dp))
 652→
 653→            // 进度条
 654→            if (task.status == DownloadStatus.DOWNLOADING) {
 655→                Column {
 656→                    Row(
 657→                        modifier = Modifier.fillMaxWidth(),
 658→                        horizontalArrangement = Arrangement.SpaceBetween
 659→                    ) {
 660→                        Text(
 661→                            "${task.progress}%",
 662→                            style = MaterialTheme.typography.bodySmall
 663→                        )
 664→                        if (task.speed > 0) {
 665→                            Text(
 666→                                formatSpeed(task.speed),
 667→                                style = MaterialTheme.typography.bodySmall,
 668→                                color = MaterialTheme.colorScheme.primary
 669→                            )
 670→                        }
 671→                    }
 672→
 673→                    Spacer(Modifier.height(4.dp))
 674→
 675→                    LinearProgressIndicator(
 676→                        progress = { task.progress / 100f },
 677→                        modifier = Modifier.fillMaxWidth(),
 678→                        color = MaterialTheme.colorScheme.primary
 679→                    )
 680→
 681→                    // 文件大小和剩余时间
 682→                    if (task.totalBytes > 0) {
 683→                        Spacer(Modifier.height(4.dp))
 684→                        Row(
 685→                            modifier = Modifier.fillMaxWidth(),
 686→                            horizontalArrangement = Arrangement.SpaceBetween
 687→                        ) {
 688→                            Text(
 689→                                "${formatFileSize(task.bytesDownloaded)} / ${formatFileSize(task.totalBytes)}",
 690→                                style = MaterialTheme.typography.bodySmall,
 691→                                color = MaterialTheme.colorScheme.onPrimaryContainer
 692→                            )
 693→                            if (task.remainingTime > 0 && task.speed > 0) {
 694→                                Text(
 695→                                    "剩余 ${formatRemainingTime(task.remainingTime)}",
 696→                                    style = MaterialTheme.typography.bodySmall,
 697→                                    color = MaterialTheme.colorScheme.onPrimaryContainer
 698→                                )
 699→                            }
 700→                        }
 701→                    }
 702→                }
 703→            } else if (task.status == DownloadStatus.FETCHING_INFO) {
 704→                Row(
 705→                    modifier = Modifier.fillMaxWidth(),
 706→                    verticalAlignment = Alignment.CenterVertically
 707→                ) {
 708→                    CircularProgressIndicator(
 709→                        modifier = Modifier.size(20.dp),
 710→                        strokeWidth = 2.dp
 711→                    )
 712→                    Spacer(Modifier.width(8.dp))
 713→                    Text(
 714→                        "正在解析视频信息...",
 715→                        style = MaterialTheme.typography.bodySmall,
 716→                        color = MaterialTheme.colorScheme.onPrimaryContainer
 717→                    )
 718→                }
 719→            } else if (task.status == DownloadStatus.FAILED) {
 720→                Row(
 721→                    modifier = Modifier.fillMaxWidth(),
 722→                    verticalAlignment = Alignment.CenterVertically
 723→                ) {
 724→                    Icon(
 725→                        Icons.Default.Error,
 726→                        contentDescription = null,
 727→                        tint = MaterialTheme.colorScheme.error,
 728→                        modifier = Modifier.size(20.dp)
 729→                    )
 730→                    Spacer(Modifier.width(8.dp))
 731→                    Text(
 732→                        task.errorMessage ?: "下载失败",
 733→                        style = MaterialTheme.typography.bodySmall,
 734→                        color = MaterialTheme.colorScheme.error
 735→                    )
 736→                }
 737→            } else if (task.status == DownloadStatus.COMPLETED) {
 738→                Row(
 739→                    modifier = Modifier.fillMaxWidth(),
 740→                    verticalAlignment = Alignment.CenterVertically
 741→                ) {
 742→                    Icon(
 743→                        Icons.Default.CheckCircle,
 744→                        contentDescription = null,
 745→                        tint = MaterialTheme.colorScheme.primary,
 746→                        modifier = Modifier.size(20.dp)
 747→                    )
 748→                    Spacer(Modifier.width(8.dp))
 749→                    Text(
 750→                        "下载完成",
 751→                        style = MaterialTheme.typography.bodySmall,
 752→                        color = MaterialTheme.colorScheme.primary
 753→                    )
 754→                }
 755→            } else if (task.status == DownloadStatus.WAITING_FOR_AUTH) {
 756→                Row(
 757→                    modifier = Modifier.fillMaxWidth(),
 758→                    verticalAlignment = Alignment.CenterVertically
 759→                ) {
 760→                    Icon(
 761→                        Icons.Default.Lock,
 762→                        contentDescription = null,
 763→                        tint = MaterialTheme.colorScheme.tertiary,
 764→                        modifier = Modifier.size(20.dp)
 765→                    )
 766→                    Spacer(Modifier.width(8.dp))
 767→                    Text(
 768→                        "需要登录获取下载权限",
 769→                        style = MaterialTheme.typography.bodySmall,
 770→                        color = MaterialTheme.colorScheme.onTertiaryContainer
 771→                    )
 772→                }
 773→            }
 774→        }
 775→    }
 776→}
